    // Output requantize + register for chip-to-chip timing
    integer j;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            chip_valid_out <= 0;
            for (j = 0; j < 8; j = j + 1)
                chip_y_out[j] <= 8'd0;
        end else begin
            chip_valid_out <= s5_valid;
            for (j = 0; j < 8; j = j + 1) begin
                if ($signed(s5_out[j]) > 16'sd127)
                    chip_y_out[j] <= 8'd127;
                else if ($signed(s5_out[j]) < -16'sd128)
                    chip_y_out[j] <= -8'd128;
                else
                    chip_y_out[j] <= s5_out[j][7:0];
            end
        end
    end

